/**
 * @name Groovy script execution with user-controlled content
 * @description Detects user-controlled input reaching Groovy script evaluation
 * @kind path-problem
 * @problem.severity error
 * @id java/groovy-injection-cps
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module GroovyInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // GroovyShell.evaluate/parse/run
    exists(MethodCall mc |
      mc.getMethod().hasName(["evaluate", "parse", "run", "runScript"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyShell") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ScriptEngine.eval
    exists(MethodCall mc |
      mc.getMethod().hasName("eval") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.script", "ScriptEngine") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // GroovyClassLoader.parseClass
    exists(MethodCall mc |
      mc.getMethod().hasName("parseClass") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyClassLoader") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module GroovyInjectionFlow = TaintTracking::Global<GroovyInjectionConfig>;
import GroovyInjectionFlow::PathGraph

from GroovyInjectionFlow::PathNode source, GroovyInjectionFlow::PathNode sink
where GroovyInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Groovy script injection: data flows from $@ to script evaluation.", source.getNode(), "remote input"

/**
 * @name Taint from StaplerRequest to Groovy script execution
 * @description Traces HTTP request data to Groovy script parsing/evaluation
 * @kind path-problem
 * @problem.severity error
 * @id java/stapler-to-groovy-exec
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module StaplerGroovyConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
    or
    // StaplerRequest getParameter, getSubmittedForm, etc.
    exists(MethodCall mc |
      mc.getMethod().hasName(["getParameter", "getSubmittedForm", "bindJSON", "bindParametersToProperties", "getJSON"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasName("StaplerRequest") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // CpsGroovyShell parse
    exists(MethodCall mc |
      mc.getMethod().hasName(["evaluate", "parse", "run", "runScript", "parseClass"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyShell") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyClassLoader")
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module StaplerGroovyFlow = TaintTracking::Global<StaplerGroovyConfig>;
import StaplerGroovyFlow::PathGraph

from StaplerGroovyFlow::PathNode source, StaplerGroovyFlow::PathNode sink
where StaplerGroovyFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Script injection from $@ to Groovy execution.", source.getNode(), "HTTP input"

/**
 * @name Complete taint from HTTP form to Groovy script execution in ReplayAction
 * @description Full path-problem query tracing HTTP form data to script execution
 * @kind path-problem
 * @problem.severity error
 * @id java/replay-full-taint-path
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module FullReplayTaintConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
    or
    // HTTP form data extraction in doRun
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasName("ReplayAction") and
      mc.getMethod().hasName(["getSubmittedForm", "getString", "get", "getParameter"]) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // CpsFlowDefinition constructor - first arg is script string
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasName("CpsFlowDefinition") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // Direct GroovyShell/ClassLoader parse call
    exists(MethodCall mc |
      mc.getMethod().hasName(["parse", "parseClass", "evaluate", "run"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyShell") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyClassLoader")
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module FullReplayTaintFlow = TaintTracking::Global<FullReplayTaintConfig>;
import FullReplayTaintFlow::PathGraph

from FullReplayTaintFlow::PathNode source, FullReplayTaintFlow::PathNode sink
where FullReplayTaintFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTTP form script content from $@ reaches Groovy execution sink.", source.getNode(), "HTTP form data"

/**
 * @name Script content parameter flows to CpsFlowDefinition with sandbox=false (trusted)
 * @description Find all paths where user script content reaches CpsFlowDefinition instantiation
 * @kind path-problem
 * @problem.severity error
 * @id java/script-to-cps-flow-definition
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ScriptToCpsConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
    or
    exists(Parameter p |
      (
        p.getCallable().getDeclaringType().hasName("ReplayAction") or
        p.getCallable().getDeclaringType().hasName("DescriptorImpl")
      ) and
      p.getCallable().getName().matches("do%") and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ReplayFlowFactoryAction constructor or CpsFlowDefinition constructor
    exists(ClassInstanceExpr ce |
      (
        ce.getConstructor().getDeclaringType().hasName("ReplayFlowFactoryAction") or
        ce.getConstructor().getDeclaringType().hasName("CpsFlowDefinition")
      ) and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module ScriptToCpsFlow = TaintTracking::Global<ScriptToCpsConfig>;
import ScriptToCpsFlow::PathGraph

from ScriptToCpsFlow::PathNode source, ScriptToCpsFlow::PathNode sink
where ScriptToCpsFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Script content from $@ reaches pipeline execution factory.", source.getNode(), "HTTP input"
